const CONTROL_CHARS = /[\u0000-\u001F\u007F]+/g;
const SAFE_SCHEMES = new Set(['http:', 'https:', 'mailto:', 'tel:']);

function stripControlChars(s) {
  return s.replace(CONTROL_CHARS, '');
}

export default function sanitizeHrefUrl(input) {
  if (input == null) return null;
  let s = String(input).trim();
  if (!s) return null;

  s = stripControlChars(s);

  // Protocol-relative and backslash-based URLs are surprising and often unsafe in app contexts.
  if (s.startsWith('//') || s.startsWith('\\\\') || s.startsWith('\\')) return null;

  // Safe relative URLs for typical SPA navigation.
  if (
    s.startsWith('#') ||
    s.startsWith('?') ||
    s.startsWith('/') ||
    s.startsWith('./') ||
    s.startsWith('../')
  ) {
    return s;
  }

  // Detect a scheme like "https:" or "javascript:".
  const match = s.match(/^([a-zA-Z][a-zA-Z0-9+.-]*):/);
  if (!match) {
    // e.g. "settings" or "profile" → treat as relative path.
    return s;
  }

  const scheme = `${match[1].toLowerCase()}:`;
  if (!SAFE_SCHEMES.has(scheme)) return null;

  if (scheme === 'http:' || scheme === 'https:') {
    try {
      return new URL(s).toString();
    } catch {
      return null;
    }
  }

  // mailto:, tel: → return as-is (trimmed + control chars stripped).
  return s;
}
